import os
import sys
import subprocess
import shutil
from pathlib import Path
from zipfile import ZipFile, ZIP_DEFLATED

ROOT = Path(__file__).resolve().parent
REQ_FILE = ROOT / "requirements.txt"
DIST_DIR = ROOT / "dist"
PACKAGE_NAME = os.environ.get("PACKAGE_NAME", "deployment_package.zip")
PACKAGE_PATH = DIST_DIR / PACKAGE_NAME


def run(cmd, check=True):
    print(f"Running: {' '.join(cmd)}")
    return subprocess.run(cmd, cwd=ROOT, check=check)


def install_dependencies():
    if REQ_FILE.exists():
        run([sys.executable, "-m", "pip", "install", "--upgrade", "pip"])
        run([sys.executable, "-m", "pip", "install", "-r", str(REQ_FILE)])
    else:
        print("requirements.txt not found, skipping dependency installation.")


def run_tests():
    if (ROOT / "pytest.ini").exists() or (ROOT / "tests").exists():
        run([sys.executable, "-m", "pytest", "-q"])
    else:
        print("No tests detected, skipping test run.")


def should_include(path: Path):
    parts = set(path.parts)
    excluded = {
        ".git",
        "__pycache__",
        ".pytest_cache",
        ".mypy_cache",
        ".tox",
        ".venv",
        "venv",
        "env",
        "dist",
        "build",
        ".idea",
        ".vscode",
    }
    return not any(p in excluded for p in parts)


def package_for_deployment():
    DIST_DIR.mkdir(exist_ok=True)
    if PACKAGE_PATH.exists():
        PACKAGE_PATH.unlink()

    with ZipFile(PACKAGE_PATH, "w", compression=ZIP_DEFLATED) as zf:
        for path in ROOT.rglob("*"):
            if path.is_file() and should_include(path):
                zf.write(path, path.relative_to(ROOT))
    print(f"Created package: {PACKAGE_PATH}")


def main():
    try:
        install_dependencies()
        run_tests()
        package_for_deployment()
        print("Deployment workflow completed successfully.")
    except subprocess.CalledProcessError as exc:
        print(f"Command failed with exit code {exc.returncode}")
        sys.exit(exc.returncode)
    except Exception as exc:
        print(f"Deployment workflow failed: {exc}")
        sys.exit(1)


if __name__ == "__main__":
    main()